const body = $input.first().json.body || $input.first().json;
const tenantId = body.tenantId || null;
const isSuperAdmin = body.isSuperAdmin === 'true';

// Si super_admin : pas de filtre tenant (voit tout)
// Sinon : filtre par tenant_id du client
const tenantFilter = isSuperAdmin ? '' : `AND ap.tenant_id = '${tenantId}'::uuid`;

return [{ json: { tenantId, isSuperAdmin, tenantFilter } }];

const g = $input.first().json;
const isSuperAdmin = $('02. Preparer').first().json.isSuperAdmin;

const nbCatalogue = Number(g.nb_catalogue) || 0;
const nbActives = Number(g.nb_actives) || 0;
const tauxAdoption = nbCatalogue > 0 ? Math.round((nbActives / nbCatalogue) * 100) : 0;

return [{ json: {
  success: true,
  data: {
    dashboard: {
      revenus: {
        mensuel: Number(g.revenu_mensuel) || 0,
        setupTotal: Number(g.revenu_setup_total) || 0,
        potentielMensuel: isSuperAdmin ? (Number(g.revenu_potentiel_mensuel) || 0) : 0,
        potentielSetup: isSuperAdmin ? (Number(g.revenu_potentiel_setup) || 0) : 0
      },
      compteurs: {
        catalogue: nbCatalogue,
        actives: nbActives,
        enAttente: Number(g.nb_en_attente) || 0,
        suspendues: Number(g.nb_suspendues) || 0,
        annulees: Number(g.nb_annulees) || 0,
        totalAchats: Number(g.nb_total_achats) || 0,
        clientsActifs: isSuperAdmin ? (Number(g.nb_clients_actifs) || 0) : 0,
        clientsTotal: isSuperAdmin ? (Number(g.nb_clients_total) || 0) : 0,
        tauxAdoption
      },
      parCategorie: [],
      parComplexite: [],
      topAutomations: [],
      topClients: []
    }
  }
} }];
